-- Table: admin_notifications
DROP TABLE IF EXISTS `admin_notifications`;
CREATE TABLE "admin_notifications" (
  "id" int NOT NULL AUTO_INCREMENT,
  "admin_id" int DEFAULT NULL,
  "title" varchar(255) NOT NULL,
  "message" text NOT NULL,
  "type" varchar(50) DEFAULT 'info',
  "is_read" tinyint(1) DEFAULT '0',
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

-- Table: admin_sessions
DROP TABLE IF EXISTS `admin_sessions`;
CREATE TABLE "admin_sessions" (
  "session_id" varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  "admin_id" int NOT NULL,
  "device" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "ip_address" varchar(45) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "last_activity" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "user_agent" text COLLATE utf8mb4_general_ci,
  "location" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "is_active" tinyint(1) DEFAULT '1',
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("session_id"),
  KEY "admin_id" ("admin_id"),
  CONSTRAINT "admin_sessions_ibfk_1" FOREIGN KEY ("admin_id") REFERENCES "admin" ("id") ON DELETE CASCADE
);

