-- Table: attendance
DROP TABLE IF EXISTS `attendance`;
CREATE TABLE "attendance" (
  "id" int NOT NULL AUTO_INCREMENT,
  "event_id" int NOT NULL,
  "member_id" int NOT NULL,
  "status" enum('Present','Late','Absent') COLLATE utf8mb4_unicode_ci NOT NULL,
  "check_in_time" time DEFAULT NULL,
  "notes" text COLLATE utf8mb4_unicode_ci,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_attendance" ("event_id","member_id"),
  KEY "idx_event" ("event_id"),
  KEY "idx_member" ("member_id"),
  KEY "idx_status" ("status"),
  CONSTRAINT "attendance_ibfk_1" FOREIGN KEY ("event_id") REFERENCES "events" ("id") ON DELETE CASCADE,
  CONSTRAINT "attendance_ibfk_2" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON DELETE CASCADE
);

-- Table: church_settings
DROP TABLE IF EXISTS `church_settings`;
CREATE TABLE "church_settings" (
  "id" int NOT NULL AUTO_INCREMENT,
  "church_name" varchar(255) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Christ-Like Christian Church',
  "church_address" text COLLATE utf8mb4_general_ci,
  "church_phone" varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "church_email" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "church_logo" longtext COLLATE utf8mb4_general_ci,
  "header_logo" longtext COLLATE utf8mb4_general_ci,
  "help_center_email" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "help_center_phone" varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "help_center_url" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "date_format" varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'mm/dd/yyyy',
  "homepage_image_1" longtext COLLATE utf8mb4_general_ci,
  "homepage_image_2" longtext COLLATE utf8mb4_general_ci,
  "homepage_image_3" longtext COLLATE utf8mb4_general_ci,
  "homepage_image_4" longtext COLLATE utf8mb4_general_ci,
  "homepage_image_5" longtext COLLATE utf8mb4_general_ci,
  "homepage_image_6" longtext COLLATE utf8mb4_general_ci,
  "homepage_hero_title" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "homepage_hero_subtitle" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

