-- Table: event_links
DROP TABLE IF EXISTS `event_links`;
CREATE TABLE "event_links" (
  "id" int NOT NULL AUTO_INCREMENT,
  "parent_event_id" int NOT NULL,
  "linked_event_id" int NOT NULL,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  KEY "parent_event_id" ("parent_event_id"),
  KEY "linked_event_id" ("linked_event_id"),
  CONSTRAINT "event_links_ibfk_1" FOREIGN KEY ("parent_event_id") REFERENCES "events" ("id") ON DELETE CASCADE,
  CONSTRAINT "event_links_ibfk_2" FOREIGN KEY ("linked_event_id") REFERENCES "events" ("id") ON DELETE CASCADE
);

-- Table: events
DROP TABLE IF EXISTS `events`;
CREATE TABLE "events" (
  "id" int NOT NULL AUTO_INCREMENT,
  "title" varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  "event_type" varchar(100) COLLATE utf8mb4_general_ci DEFAULT 'Service',
  "date" date NOT NULL,
  "start_time" time NOT NULL,
  "end_time" time NOT NULL,
  "location" varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  "status" enum('upcoming','active','completed') COLLATE utf8mb4_general_ci DEFAULT 'upcoming',
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  "auto_ended" tinyint(1) DEFAULT '0',
  "manually_ended" tinyint(1) DEFAULT '0',
  PRIMARY KEY ("id")
);

INSERT INTO `events` (`id`, `title`, `event_type`, `date`, `start_time`, `end_time`, `location`, `status`, `created_at`, `updated_at`, `auto_ended`, `manually_ended`) VALUES
