-- Table: family_relationships
DROP TABLE IF EXISTS `family_relationships`;
CREATE TABLE "family_relationships" (
  "id" int NOT NULL AUTO_INCREMENT,
  "member_id" int NOT NULL,
  "relative_id" int NOT NULL,
  "relationship_type" enum('Spouse','Father','Mother','Son','Daughter','Brother','Sister','Other') COLLATE utf8mb4_unicode_ci NOT NULL,
  "status" enum('pending','accepted','declined','removed') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  "initiated_at" datetime DEFAULT CURRENT_TIMESTAMP,
  "responded_at" datetime DEFAULT NULL,
  "notes" varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "created_by" int DEFAULT NULL,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_relationship" ("member_id","relative_id"),
  KEY "created_by" ("created_by"),
  KEY "idx_member_id" ("member_id"),
  KEY "idx_relative_id" ("relative_id"),
  KEY "idx_status" ("status"),
  CONSTRAINT "family_relationships_ibfk_1" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON DELETE CASCADE,
  CONSTRAINT "family_relationships_ibfk_2" FOREIGN KEY ("relative_id") REFERENCES "members" ("id") ON DELETE CASCADE,
  CONSTRAINT "family_relationships_ibfk_3" FOREIGN KEY ("created_by") REFERENCES "members" ("id") ON DELETE SET NULL
);

-- Table: guest_attendance
DROP TABLE IF EXISTS `guest_attendance`;
CREATE TABLE "guest_attendance" (
  "id" int NOT NULL AUTO_INCREMENT,
  "guest_id" int NOT NULL,
  "session_id" int NOT NULL,
  "event_id" int DEFAULT NULL,
  "status" enum('present','late') COLLATE utf8mb4_unicode_ci DEFAULT 'present',
  "checkin_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "source" enum('qr','manual') COLLATE utf8mb4_unicode_ci DEFAULT 'qr',
  "notes" text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_guest_session" ("guest_id","session_id"),
  KEY "idx_guest_id" ("guest_id"),
  KEY "idx_session_id_guest" ("session_id"),
  KEY "idx_event_id_guest" ("event_id"),
  CONSTRAINT "fk_guest_attendance_event" FOREIGN KEY ("event_id") REFERENCES "events" ("id") ON DELETE SET NULL,
  CONSTRAINT "fk_guest_attendance_guest" FOREIGN KEY ("guest_id") REFERENCES "guests" ("id") ON DELETE CASCADE,
  CONSTRAINT "fk_guest_attendance_session" FOREIGN KEY ("session_id") REFERENCES "qr_sessions" ("id") ON DELETE CASCADE
);

-- Table: guests
DROP TABLE IF EXISTS `guests`;
CREATE TABLE "guests" (
  "id" int NOT NULL AUTO_INCREMENT,
  "first_name" varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  "middle_name" varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "surname" varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  "suffix" varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "full_name" varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  "contact_number" varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "email" varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "invited_by_member_id" int DEFAULT NULL,
  "invited_by_text" varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "notes" text COLLATE utf8mb4_unicode_ci,
  "first_visit_date" date DEFAULT NULL,
  "last_visit_date" date DEFAULT NULL,
  "status" enum('active','converted','archived') COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_guest_contact" ("contact_number","email"),
  KEY "idx_guest_name" ("full_name"),
  KEY "idx_guest_status" ("status"),
  KEY "fk_guests_invited_by_member" ("invited_by_member_id"),
  CONSTRAINT "fk_guests_invited_by_member" FOREIGN KEY ("invited_by_member_id") REFERENCES "members" ("id") ON DELETE SET NULL
);

-- Table: legal_pages
DROP TABLE IF EXISTS `legal_pages`;
CREATE TABLE "legal_pages" (
  "id" int NOT NULL AUTO_INCREMENT,
  "slug" varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  "title" varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  "content" mediumtext COLLATE utf8mb4_unicode_ci NOT NULL,
  "updated_by" varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  UNIQUE KEY "slug" ("slug")
);

-- Table: linked_events
DROP TABLE IF EXISTS `linked_events`;
CREATE TABLE "linked_events" (
  "id" int NOT NULL AUTO_INCREMENT,
  "event_id_1" int NOT NULL,
  "event_id_2" int NOT NULL,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_link" ("event_id_1","event_id_2"),
  KEY "event_id_2" ("event_id_2"),
  CONSTRAINT "linked_events_ibfk_1" FOREIGN KEY ("event_id_1") REFERENCES "events" ("id") ON DELETE CASCADE,
  CONSTRAINT "linked_events_ibfk_2" FOREIGN KEY ("event_id_2") REFERENCES "events" ("id") ON DELETE CASCADE,
  CONSTRAINT "CONSTRAINT_1" CHECK ((`event_id_1` < `event_id_2`))
);

-- Table: login_history
DROP TABLE IF EXISTS `login_history`;
CREATE TABLE "login_history" (
  "id" int NOT NULL AUTO_INCREMENT,
  "admin_id" int NOT NULL,
  "ip_address" varchar(45) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "user_agent" text COLLATE utf8mb4_general_ci,
  "device" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "browser" varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "location" varchar(100) COLLATE utf8mb4_general_ci DEFAULT 'Unknown',
  "login_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "is_current" tinyint(1) DEFAULT '0',
  PRIMARY KEY ("id"),
  KEY "admin_id" ("admin_id"),
  CONSTRAINT "login_history_ibfk_1" FOREIGN KEY ("admin_id") REFERENCES "admin" ("id") ON DELETE CASCADE
);

