-- Table: members
DROP TABLE IF EXISTS `members`;
CREATE TABLE "members" (
  "id" int NOT NULL AUTO_INCREMENT,
  "surname" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "first_name" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "middle_name" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "suffix" enum('None','Jr.','Sr.','II','III','IV') COLLATE utf8mb4_general_ci DEFAULT 'None',
  "gender" enum('Male','Female','Other','Prefer not to say') COLLATE utf8mb4_general_ci DEFAULT 'Prefer not to say',
  "username" varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  "email" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "profile_picture" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "contact_number" varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "guardian_surname" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "guardian_first_name" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "guardian_middle_name" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "guardian_suffix" enum('None','Jr.','Sr.','II','III','IV') COLLATE utf8mb4_general_ci DEFAULT 'None',
  "relationship_to_guardian" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "street" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "barangay" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "city" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "province" varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "zip_code" varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "referrer_id" int DEFAULT NULL,
  "referrer_name" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "relationship_to_referrer" enum('Friend','Family Member','Colleague','Neighbor','Acquaintance','Other') COLLATE utf8mb4_general_ci DEFAULT NULL,
  "password" varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  "must_change_password" tinyint(1) NOT NULL DEFAULT '0',
  "password_temp_expires_at" datetime DEFAULT NULL,
  "birthday" date NOT NULL,
  "status" enum('pending','active','inactive','rejected') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'pending',
  "manager_status" enum('pending','approved','rejected') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'pending',
  "manager_reviewed_at" datetime DEFAULT NULL,
  "manager_note" text COLLATE utf8mb4_general_ci,
  "rejection_reason" text COLLATE utf8mb4_general_ci,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  "full_name" varchar(300) COLLATE utf8mb4_general_ci GENERATED ALWAYS AS (concat(`first_name`,_utf8mb4' ',if(((`middle_name` is not null) and (`middle_name` <> _utf8mb4'')),concat(`middle_name`,_utf8mb4' '),_utf8mb4''),`surname`,if((`suffix` <> _utf8mb4'None'),concat(_utf8mb4' ',`suffix`),_utf8mb4''))) STORED,
  "full_address" varchar(500) COLLATE utf8mb4_general_ci GENERATED ALWAYS AS (concat(`street`,_utf8mb4', ',`barangay`,_utf8mb4', ',`city`,_utf8mb4', ',`province`,_utf8mb4' ',`zip_code`)) STORED,
  "attendance_streak" int DEFAULT '0',
  PRIMARY KEY ("id"),
  UNIQUE KEY "username" ("username"),
  KEY "idx_members_status" ("status"),
  KEY "idx_members_city" ("city"),
  KEY "idx_members_province" ("province"),
  KEY "referrer_id" ("referrer_id"),
  CONSTRAINT "members_ibfk_1" FOREIGN KEY ("referrer_id") REFERENCES "members" ("id") ON DELETE SET NULL
);

