-- Table: notification_reads
DROP TABLE IF EXISTS `notification_reads`;
CREATE TABLE "notification_reads" (
  "id" int NOT NULL AUTO_INCREMENT,
  "notification_id" int NOT NULL,
  "user_id" int NOT NULL,
  "user_type" varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT 'admin or manager',
  "read_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_notification_user" ("notification_id","user_id","user_type"),
  KEY "notification_id" ("notification_id"),
  KEY "user_id" ("user_id"),
  KEY "user_type" ("user_type"),
  CONSTRAINT "notification_reads_ibfk_1" FOREIGN KEY ("notification_id") REFERENCES "notifications" ("id") ON DELETE CASCADE
);

