-- Table: password_reset_requests
DROP TABLE IF EXISTS `password_reset_requests`;
CREATE TABLE "password_reset_requests" (
  "id" int NOT NULL AUTO_INCREMENT,
  "member_id" int NOT NULL,
  "status" enum('pending','completed','cancelled') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'pending',
  "requested_at" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "processed_at" datetime DEFAULT NULL,
  "processed_by_admin_id" int DEFAULT NULL,
  "admin_note" text COLLATE utf8mb4_general_ci,
  "temporary_password_hash" varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  "temporary_password_expires_at" datetime DEFAULT NULL,
  PRIMARY KEY ("id"),
  KEY "idx_member_status" ("member_id","status"),
  CONSTRAINT "fk_reset_member" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON DELETE CASCADE
);

