-- Table: qr_attendance
DROP TABLE IF EXISTS `qr_attendance`;
CREATE TABLE "qr_attendance" (
  "id" int NOT NULL AUTO_INCREMENT,
  "session_id" int NOT NULL,
  "member_id" int DEFAULT NULL,
  "member_name" varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "member_contact" varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "checkin_datetime" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "ip_address" varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  "user_agent" text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY ("id"),
  UNIQUE KEY "unique_member_session" ("session_id","member_id"),
  KEY "idx_session_id" ("session_id"),
  KEY "idx_member_id" ("member_id"),
  KEY "idx_checkin_datetime" ("checkin_datetime"),
  CONSTRAINT "qr_attendance_ibfk_1" FOREIGN KEY ("session_id") REFERENCES "qr_sessions" ("id") ON DELETE CASCADE
);

