-- Table: qr_sessions
DROP TABLE IF EXISTS `qr_sessions`;
CREATE TABLE "qr_sessions" (
  "id" int NOT NULL AUTO_INCREMENT,
  "session_token" varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  "service_name" varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  "event_datetime" datetime NOT NULL,
  "event_type" enum('preset','custom') COLLATE utf8mb4_unicode_ci DEFAULT 'preset',
  "session_type" enum('member','guest') COLLATE utf8mb4_unicode_ci DEFAULT 'member',
  "created_by" int DEFAULT NULL,
  "status" enum('active','expired','completed') COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  "scan_count" int DEFAULT '0',
  "event_id" int DEFAULT NULL,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  UNIQUE KEY "session_token" ("session_token"),
  KEY "idx_session_token" ("session_token"),
  KEY "idx_status" ("status"),
  KEY "idx_event_datetime" ("event_datetime"),
  KEY "idx_event_id" ("event_id"),
  KEY "idx_session_type" ("session_type"),
  CONSTRAINT "fk_qr_sessions_event" FOREIGN KEY ("event_id") REFERENCES "events" ("id") ON DELETE SET NULL
);

